  "trivia": [
    {
      "id": "1982-first-24-teams",
      "year": 1982,
      "category": "format",
      "fact": "1982 was the first World Cup with 24 teams (expanded from 16). Format: 6 groups of 4 → 4 second-round groups of 3 → SF / 3rd / Final. The format wasn't repeated; 1986 introduced the modern knockout from R16.",
      "teams": []
    },
    {
      "id": "1982-disgrace-of-gijon",
      "year": 1982,
      "category": "matches",
      "fact": "The 'Disgrace of Gijón' — West Germany 1-0 Austria, 25 June 1982. After Hrubesch's 10th-minute goal, both teams played out the rest of the match, knowing the result would advance both at Algeria's expense (Algeria had played the day before). FIFA changed the format the next tournament so final group games kicked off simultaneously.",
      "teams": [
        "West Germany",
        "Austria",
        "Algeria"
      ]
    },
    {
      "id": "1982-rossi-redemption",
      "year": 1982,
      "category": "awards",
      "fact": "Paolo Rossi won the Golden Boot (6 goals) and Golden Ball at 1982 — extraordinary because he had returned from a 2-year ban for match-fixing just months before the tournament. He scored a hat-trick vs Brazil (3-2), 2 in SF vs Poland, 1 in the final.",
      "players": [
        "Paolo Rossi"
      ],
      "teams": [
        "Italy"
      ]
    },
    {
      "id": "1982-first-shootout",
      "year": 1982,
      "category": "firsts",
      "fact": "West Germany 5-4 France (3-3 after extra time) in the 1982 SF was the first penalty shootout in World Cup history. The match also featured Harald Schumacher's notorious challenge on Patrick Battiston — one of the most controversial fouls in WC history — for which no card was shown.",
      "teams": [
        "West Germany",
        "France"
      ]
    },
    {
      "id": "1982-five-debuts",
      "year": 1982,
      "category": "firsts",
      "fact": "Algeria, Cameroon, Honduras, Kuwait, and New Zealand all made their World Cup debuts at 1982 — five debutants in one tournament, made possible by expansion to 24 teams.",
      "teams": [
        "Algeria",
        "Cameroon",
        "Honduras",
        "Kuwait",
        "New Zealand"
      ]
    }
  ],
